mapper.insert:
/* 파일: 행 추가 */
INSERT INTO FILES (
    FL_ORG_NM, FL_SAVE_NM, FL_PATH, FL_EXT, FL_SIZE_AMT, FL_TYPE_CD, FL_REG_ID
) VALUES (
    #{flOrgNm}, #{flSaveNm}, #{flPath}, #{flExt}, #{flSizeAmt}, #{flTypeCd}, #{flRegId}
)

mapper.select:
/* 파일: 상품이미지 참조 수 */
SELECT COUNT(*)
  FROM PRODUCT_IMAGE
 WHERE FL_SN = #{flSn}

/* 파일: 제공자 신청-파일 연결 확인 (관리자 열람 가드, 읽기 전용) */
SELECT COUNT(*)
  FROM PROVIDER_APPLY_FILE
 WHERE PRV_APLY_SN = #{prvAplySn}
   AND FL_SN = #{flSn}

/* 파일: 배송-파일 연결 확인 (당사자 열람 가드) */
SELECT COUNT(*)
  FROM TRADE_DELIVERY_FILE
 WHERE TRD_DLVR_SN = #{trdDlvrSn}
   AND FL_SN = #{flSn}

/* 파일: 배송 건 거래 당사자 확인 (읽기 전용) */
SELECT COUNT(*)
  FROM TRADE_DELIVERY D
  JOIN TRADE T ON T.TRD_SN = D.TRD_SN
 WHERE D.TRD_DLVR_SN = #{trdDlvrSn}
   AND (T.SLLR_USR_SN = #{usrSn} OR T.BYPR_USR_SN = #{usrSn})

/* 파일: 배송인증사진 참조 수 */
SELECT COUNT(*)
  FROM TRADE_DELIVERY_FILE
 WHERE FL_SN = #{flSn}

/* 파일: 리뷰이미지 참조 수 */
SELECT COUNT(*)
  FROM REVIEW_IMAGE
 WHERE FL_SN = #{flSn}
